insert into public.brands (id, name, is_visible, detail) values
  ('b1', '페네핏 (PENEFIT)', true, '{"officialUrl":"https://penefit.co.kr/","sourceUrls":["https://penefit.co.kr/product/%ED%8C%94%EB%A0%88%ED%8A%B8%ED%8C%8C%EC%9A%B0%EB%8D%94-20-%EB%A3%A8%ED%8B%B4-%EC%BC%80%EC%96%B4-5%EC%A2%85/90/","https://penefit.co.kr/product/%ED%8E%98%EB%84%A4%ED%95%8F-%EB%8F%99%EA%B2%B0%EA%B1%B4%EC%A1%B0-%ED%8A%B8%EB%A6%BF-%EC%A0%B8%ED%82%A4-%EA%B0%84%EC%8B%9D-7%EC%A2%85/78/"],"logo":"/brands/penefit-official.png","description":"반려동물의 식탁을 더 즐겁고 건강하게 만드는 영양 토핑 브랜드","philosophy":"페네핏은 반려동물의 식사 시간을 단순히 배를 채우는 순간이 아니라,\n건강한 즐거움과 기록이 함께 쌓이는 시간으로 바라봅니다.\n\n한 끼의 즐거움이 내일의 건강으로 이어지는 것.\n페네핏은 그 작고 꾸준한 다정함을 제품으로 제안합니다.","auditPoints":["식사 보조 제품으로 활용하기 쉬운 구성","강아지와 고양이 모두를 고려한 제품 라인","다양한 맛 옵션으로 기호성 선택 가능","소분 또는 샘플 형태 구매 흐름에 적합","보호자가 급여 반응을 확인하기 쉬운 제품 구조"],"auditReport":{"reportNo":"BOA-2026-004","auditedAt":"2026.06","status":"Audit Completed","headline":"반려동물의 식탁을 넓히는 영양 설계","summaryTitle":"성분을 감추지 않는 자신감","summary":"좋은 간식은 아이들이 즐겁게 먹을 수 있어야 하지만, 맛만으로 충분하지 않습니다. 페네핏은 기호성 뒤의 영양 설계와 원료 공개, 특정 아이들이 먹지 못하는 상황까지 함께 고민합니다.","selectionReason":"반려동물 간식은 많지만 더 많은 아이들이 함께 먹을 수 있는 방법까지 고민하는 브랜드는 많지 않습니다. 페네핏은 단순히 기호성만 앞세우지 않고, 알레르기 반응으로 기존 제품을 먹기 어려운 아이들까지 고려해 별도의 레시피를 개발하고 있었습니다. 원료와 맞춤 영양 설계, 반려동물 식품영양사 참여 여부, 국내 생산 체계와 실제 운영 태도를 함께 검토한 결과 제품 운영 전반에 반려동물 중심의 기준이 반영돼 있음을 확인했습니다.","process":["브랜드 철학 및 제품 개발 방향성","반려동물 식품영양사 참여 여부","원료 선정 및 영양 설계 방식","국내 생산 체계 및 품질 관리 기준","알레르기 대응 제품 개발 과정","실제 운영 태도 및 브랜드 문화","제품 확장 계획 및 지속 가능성"]},"representativeProductIds":["p1","p2","p3"],"relatedConcernSlugs":["picky","nutrition"],"isRecommended":true}'::jsonb),
  ('b2', '오미프로 (OMIPRO)', true, '{"officialUrl":"http://www.omipro.co.kr/","sourceUrls":["https://exhi.daara.co.kr/akppe/m/view.php?idx=308611&language_chk=en","https://exhi.daara.co.kr/akppe/view.php?idx=308612","https://buykorea.org/ec/prd/selectSvcDetail.do?goodsSn=3703785"],"logo":"/brands/omipro-official.png","description":"반려동물의 체취와 분변 냄새 관리를 위한 기능성 사료형 간식 브랜드","philosophy":"오미프로는 반려동물의 식사 루틴 안에서 냄새 고민을 관리하는 방법을 제안합니다.\n\n제품의 기능과 급여 방법을 명확히 안내하고, 치료를 대신하지 않는 생활 관리의 언어를 지향합니다.","auditPoints":["강아지용 OMIPRO-D와 고양이용 OMIPRO-C 라인 구분","사료에 섞거나 간식처럼 급여할 수 있는 형태","체취·분변 냄새 저감 목적의 명확한 제품 방향","기능성 표현은 자료 확인 후 백조오브제 기준으로 검수","수의학적 치료 효능으로 오인되지 않도록 관리 중심 안내"],"representativeProductIds":["p4","p5","p6"],"relatedConcernSlugs":["digestion","skin"],"isRecommended":true}'::jsonb),
  ('b3', '노블독 (NobleDog)', true, '{"sourceUrls":["https://www.coupang.com/vp/products/8769224002","https://www.coupang.com/vp/products/9305418924"],"logo":"/brands/nobledog-clean.png","description":"반려동물의 구강 건강을 위한 집요한 케어 브랜드","philosophy":"노블독은 반려동물의 구강 건강을 중심으로 제품을 설계하는 브랜드입니다.\n\n팔기 위한 제품이 아닌, 살리기 위한 집요함.\n노블독은 느리지만 단단한 길을 선택한 브랜드입니다.","auditPoints":["구강 건강 중심의 명확한 제품 방향","공식 제조·성분·시험 자료 수령 후 입점 검수","구취·프라그 관련 표현은 확인된 근거 범위에서만 사용","보호자가 사용하기 쉬운 스프레이형 제품 구조","직접 분사 또는 물/사료에 섞어 사용할 수 있는 편의성"],"representativeProductIds":["p7","p8"],"relatedConcernSlugs":["oral"],"isRecommended":true}'::jsonb),
  ('b4', '캣코드 (Catcode)', false, '{"logo":"/brands/catcode.svg","description":"고양이와 보호자의 교감을 위한 브러싱 케어 브랜드","philosophy":"캣코드는 고양이의 편안함과 보호자의 다정한 손길을 함께 고려한 케어 브랜드입니다.\n\n당신이 받은 고결한 사랑에 답하는 가장 다정한 언어.\n캣코드는 관리가 아닌 교감의 시간을 제안합니다.","auditPoints":["고양이가 거부감 없이 받아들이기 쉬운 케어 방향","보호자와 고양이의 관계성을 고려한 제품 구조","손가락 사이에 자연스럽게 안정되는 손잡이 설계","브러싱과 마사지가 함께 가능한 사용 경험","공간과 감성을 해치지 않는 오브제형 디자인"],"representativeProductIds":["p9","p10","p11"],"relatedConcernSlugs":["grooming","stress"],"isRecommended":false,"isNew":true}'::jsonb),
  ('b5', '알로밍 (ALLOMING)', true, '{"officialUrl":"https://alloming.com/","sourceUrls":["https://alloming.com/shop_view/?idx=13","https://alloming.com/shop_view/?idx=6","https://alloming.com/certifications"],"logo":"/brands/alloming-official.png","description":"반려동물과 보호자의 교감을 위한 트루그루밍 브러시 브랜드","philosophy":"알로밍은 브러싱을 단순한 털 관리가 아니라 반려동물과 보호자가 서로를 돌보는 시간으로 바라봅니다.\n\n손에 잡히는 사용감과 모듈 구조를 함께 설계해 매일의 그루밍 루틴을 제안합니다.","auditPoints":["강아지·고양이 공용 그루밍 브러시","단모·장모용 모듈 구분","브러싱과 보호자 교감 경험을 함께 고려","국내 브랜드·제조 정보 확인 가능","색상과 모듈을 선택할 수 있는 상품 구조"],"representativeProductIds":["p12","p13","p14"],"relatedConcernSlugs":["grooming","stress","living"],"isRecommended":false,"isNew":true}'::jsonb),
  ('b6', 're펫 (RePet)', true, '{"sourceUrls":["https://www.coupang.com/vp/products/7940009634","https://www.coupang.com/vp/products/4581101510","https://www.coupang.com/vp/products/7856404250","https://www.coupang.com/vp/products/9334824830","https://www.coupang.com/vp/products/8309521234"],"logo":"/brands/repet-display.svg","description":"장 건강·위생·생활 케어 상품 후보를 확인 중인 브랜드","philosophy":"re펫은 현재 공개 판매 페이지에서 상품 후보를 수집한 단계입니다.\n\n공식 제조사와 브랜드 운영 주체를 확인한 뒤 백조오브제의 판매 상품으로 최종 승인합니다.","auditPoints":["공식 운영 주체와 제조사 확인 필요","장 건강·샴푸·배변 유도제·분유 상품군 후보","상품별 성분·사용법·품질 자료 확인 필요","검증 완료 전 과장된 기능성 문구 사용 금지","출처 URL은 관리자 검수용으로만 보관"],"representativeProductIds":["p19","p20"],"relatedConcernSlugs":["digestion","skin"],"isRecommended":false,"isNew":true}'::jsonb),
  ('b7', '메종슈슈 (Maison Chouchou)', true, '{"officialUrl":"https://maisonchouchou-pet.com/","sourceUrls":["https://maisonchouchou-pet.com/product/for-ur-dog-bamboo-cardigan/163/","https://maisonchouchou-pet.com/product/gold-ops/191","https://maisonchouchou-pet.com/product/atelier-angel-dresspink/199/","https://maisonchouchou-pet.com/product/%EB%A9%94%EC%A2%85%EC%8A%88%EC%8A%88-%EB%A6%AC%EB%B3%B8-%EC%A7%84%EC%A3%BC-%EB%AA%A9%EA%B1%B8%EC%9D%B4/205"],"logo":"/brands/maison-chouchou-official.png","description":"반려견을 위한 의류와 액세서리를 제안하는 패션 브랜드","philosophy":"메종슈슈는 반려견의 일상과 특별한 순간을 위한 의류와 액세서리를 만듭니다.\n\n사이즈와 제작·배송 조건을 함께 안내하는 섬세한 패션 경험을 제안합니다.","auditPoints":["반려견 의류·드레스·목걸이 상품군","상품별 사이즈 선택이 중요한 카테고리","핸드메이드·소량 제작 상품의 배송 기간 확인","주문 제작 상품 교환·반품 조건 별도 안내","백조오브제 내부 배송 정책과 조율 필요"],"representativeProductIds":["p15","p16"],"relatedConcernSlugs":["stress","living"],"isRecommended":true,"isNew":true}'::jsonb),
  ('b8', '챠콜스토리 (Charcoal Story)', true, '{"officialUrl":"https://charcoalstory.com/","sourceUrls":["https://www.coupang.com/vp/products/9468681405","https://www.coupang.com/vp/products/9479160233","https://www.coupang.com/vp/products/9468730890","https://www.coupang.com/vp/products/9466864793"],"logo":"/brands/charcoal-story-official.png","description":"참숯 소재를 활용한 반려동물 탈취·생활 케어 브랜드","philosophy":"챠콜스토리는 참숯 소재의 특성을 반려동물의 생활 공간에 맞게 제안합니다.\n\n고양이 화장실과 방석 주변을 더 쾌적하게 관리하는 생활 케어를 지향합니다.","auditPoints":["고양이 모래 탈취제와 참숯 탈취 매트 상품군","반려동물 사용 공간에 맞는 제품만 선별","어항·화분용 상품은 반려동물관에서 제외","소재·사용 기간·교체 방법 확인 필요","탈취 표현은 제품 자료 범위 내에서 안내"],"representativeProductIds":["p17","p18"],"relatedConcernSlugs":["digestion","living"],"isRecommended":true,"isNew":true}'::jsonb),
  ('b9', '써니 사이드업 (Sunny Side Up)', true, '{"officialUrl":"https://www.ssup.co.kr/","sourceUrls":["https://www.ssup.co.kr/goods/view?no=38","https://ssup.co.kr/goods/view?no=43","https://www.ssup.co.kr/service/company"],"logo":"/brands/sunny-side-up-official.png","description":"애니마크·퍼르르펙트·파티애니멀을 운영하는 펫 라이프스타일 브랜드","philosophy":"써니 사이드업은 반려동물과 사람이 함께 더 즐겁게 살아가는 제품을 만듭니다.\n\n운영 브랜드와 개별 제품 브랜드를 분리해, 사용 대상과 기능을 정확하게 안내합니다.","auditPoints":["애니마크 반려동물 피부 연고 상품 확인","퍼르르펙트·파티애니멀 등 제품 브랜드 구분","반려동물용과 사람용 상품을 분리 노출","피부 케어 상품의 사용 대상·주의사항 확인","향수·장난감·케어 제품으로 확장 가능한 구조"],"representativeProductIds":["p21","p22"],"relatedConcernSlugs":["skin","stress"],"isRecommended":true,"isNew":true}'::jsonb)
insert into public.products (id, brand_id, name, price, sale_price, category, category_slug, lifestyle_category, pet_type, stock, rating, review_count, is_visible, is_best, is_recommended, detail) values
